import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getVideoInsights = async (title: string, description: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Provide 3 key insights or interesting facts related to a video titled "${title}". 
      Description: "${description}". 
      Format as a concise JSON list of strings.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.STRING
          }
        }
      }
    });

    return JSON.parse(response.text.trim()) as string[];
  } catch (error) {
    console.error("Gemini Insights Error:", error);
    return ["AI is currently processing insights for this video...", "Stay tuned for more context!", "Recommended for you based on current trends."];
  }
};

export const getSmartSearch = async (query: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `The user is searching for "${query}" on a video platform. 
      Generate 3 highly relevant, trending search terms related to this.
      Format as JSON array of strings.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.STRING
          }
        }
      }
    });
    return JSON.parse(response.text.trim()) as string[];
  } catch (error) {
    return [query, `${query} tutorial`, `${query} review`];
  }
};

