import React, { useState, useEffect, useMemo } from 'react';
import Navbar from './components/Navbar';
import Sidebar from './components/Sidebar';
import VideoCard from './components/VideoCard';
import VideoDetail from './components/VideoDetail';
import { MOCK_VIDEOS, CATEGORIES } from './constants';
import { Video } from './types';

const App: React.FC = () => {
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [activeTab, setActiveTab] = useState('home');
  const [activeCategory, setActiveCategory] = useState('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [currentVideoId, setCurrentVideoId] = useState<string | null>(null);

  // Simple Hash-based Routing
  useEffect(() => {
    const handleHashChange = () => {
      const hash = window.location.hash;
      if (hash.startsWith('#video/')) {
        setCurrentVideoId(hash.replace('#video/', ''));
      } else {
        setCurrentVideoId(null);
      }
    };

    window.addEventListener('hashchange', handleHashChange);
    handleHashChange(); // Initial check

    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  const filteredVideos = useMemo(() => {
    return MOCK_VIDEOS.filter(v => {
      const matchesCategory = activeCategory === 'all' || v.category === activeCategory;
      const matchesSearch = v.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
                           v.channelName.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [activeCategory, searchQuery]);

  const currentVideo = useMemo(() => {
    return MOCK_VIDEOS.find(v => v.id === currentVideoId) || null;
  }, [currentVideoId]);

  const handleVideoClick = (id: string) => {
    window.location.hash = `#video/${id}`;
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar 
        onSearch={setSearchQuery} 
        toggleSidebar={() => setSidebarOpen(!isSidebarOpen)} 
      />

      <div className="flex flex-1 pt-16">
        <Sidebar 
          isOpen={isSidebarOpen} 
          activeTab={activeTab} 
          setActiveTab={setActiveTab} 
        />

        <main className={`flex-1 transition-all duration-300 ${isSidebarOpen ? 'sm:ml-64' : 'sm:ml-20'}`}>
          {currentVideo ? (
            <VideoDetail video={currentVideo} />
          ) : (
            <div className="p-4 md:p-6">
              {/* Categories */}
              <div className="flex items-center gap-2 overflow-x-auto pb-4 sticky top-16 bg-slate-950 z-30 scrollbar-hide py-2">
                {CATEGORIES.map(cat => (
                  <button
                    key={cat.id}
                    onClick={() => setActiveCategory(cat.id)}
                    className={`px-4 py-2 rounded-xl text-sm font-semibold whitespace-nowrap transition-all border ${
                      activeCategory === cat.id
                        ? 'bg-white text-black border-white shadow-lg shadow-white/10'
                        : 'bg-slate-900 text-slate-400 border-slate-800 hover:bg-slate-800 hover:text-white'
                    }`}
                  >
                    {cat.label}
                  </button>
                ))}
              </div>

              {/* Feed Grid */}
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-x-6 gap-y-10 mt-4 animate-in fade-in duration-700">
                {filteredVideos.length > 0 ? (
                  filteredVideos.map((video, idx) => (
                    <div 
                      key={video.id} 
                      className="animate-in slide-in-from-bottom-6 duration-700"
                      style={{ animationDelay: `${idx * 50}ms` }}
                    >
                      <VideoCard video={video} onClick={handleVideoClick} />
                    </div>
                  ))
                ) : (
                  <div className="col-span-full flex flex-col items-center justify-center py-20 text-slate-500">
                    <Sparkles size={48} className="text-slate-800 mb-4" />
                    <p className="text-xl font-medium">No results found for your search.</p>
                    <button 
                      onClick={() => { setSearchQuery(''); setActiveCategory('all'); }}
                      className="mt-4 text-indigo-400 hover:underline font-medium"
                    >
                      Reset all filters
                    </button>
                  </div>
                )}
              </div>
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

